/**
 * @file fft_radix16_avx512_dit_tw_log3.h
 * @brief DFT-16 AVX512 DIT twiddled (log3 derived)
 *
 * 4x4 CT, k-step=8
 * Generated by gen_radix16.py
 *
 * ── Operation counts per k-step ──
 *
 *   kernel                 add   sub   mul   neg   fma   fms | arith flops |  ld  st  sp  rl  mem
 *   ──────────────────── ───── ───── ───── ───── ───── ───── + ───── ───── + ─── ─── ─── ─── ────
 *   bwd                     68    68    68     3    30    30 |   267   327 |  40  32  16  16  104
 *   fwd                     68    68    68     3    30    30 |   267   327 |  40  32  16  16  104
 *
 */

#ifndef FFT_RADIX16_AVX512_DIT_TW_LOG3_H
#define FFT_RADIX16_AVX512_DIT_TW_LOG3_H

#include <immintrin.h>

#ifndef FFT_W16_TWIDDLES_DEFINED
#define FFT_W16_TWIDDLES_DEFINED
static const double W16_1_re = 9.23879532511286738483e-01;
static const double W16_1_im = -3.82683432365089781779e-01;
static const double W16_3_re = 3.82683432365089837290e-01;
static const double W16_3_im = -9.23879532511286738483e-01;
static const double W16_9_re = -9.23879532511286849505e-01;
static const double W16_9_im = 3.82683432365089670757e-01;
#endif

#ifndef R16L_LD
#define R16L_LD(p) _mm512_load_pd(p)
#endif
#ifndef R16L_ST
#define R16L_ST(p,v) _mm512_store_pd((p),(v))
#endif
#define LD R16L_LD
#define ST R16L_ST

static __attribute__((target("avx512f,avx512dq,fma"))) void
radix16_tw_log3_dit_kernel_fwd_avx512(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    const double * __restrict__ base_tw_re, const double * __restrict__ base_tw_im,
    size_t K)
{
    const __m512d sign_flip = _mm512_set1_pd(-0.0);
    const __m512d sqrt2_inv = _mm512_set1_pd(0.70710678118654752440);

    __attribute__((aligned(64))) double spill_re[128];
    __attribute__((aligned(64))) double spill_im[128];

    __m512d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im;

    /* Hoisted internal W16 broadcasts [fwd] */
    const __m512d tw_W16_1_re = _mm512_set1_pd(W16_1_re);
    const __m512d tw_W16_1_im = _mm512_set1_pd(W16_1_im);
    const __m512d tw_W16_3_re = _mm512_set1_pd(W16_3_re);
    const __m512d tw_W16_3_im = _mm512_set1_pd(W16_3_im);
    const __m512d tw_W16_9_re = _mm512_set1_pd(W16_9_re);
    const __m512d tw_W16_9_im = _mm512_set1_pd(W16_9_im);

    for (size_t k = 0; k < K; k += 8) {
        /* Load 4 log3 base twiddles: W^1, W^2, W^4, W^8 */
        const __m512d b1_re = _mm512_load_pd(&base_tw_re[0*K+k]);
        const __m512d b1_im = _mm512_load_pd(&base_tw_im[0*K+k]);
        const __m512d b2_re = _mm512_load_pd(&base_tw_re[1*K+k]);
        const __m512d b2_im = _mm512_load_pd(&base_tw_im[1*K+k]);
        const __m512d b4_re = _mm512_load_pd(&base_tw_re[2*K+k]);
        const __m512d b4_im = _mm512_load_pd(&base_tw_im[2*K+k]);
        const __m512d b8_re = _mm512_load_pd(&base_tw_re[3*K+k]);
        const __m512d b8_im = _mm512_load_pd(&base_tw_im[3*K+k]);

        __m512d tw_dr, tw_di;

        /* sub-FFT n2=0 */
        x0_re = LD(&in_re[0*K+k]);
        x0_im = LD(&in_im[0*K+k]);
        x1_re = LD(&in_re[4*K+k]);
        x1_im = LD(&in_im[4*K+k]);
        { __m512d tr = x1_re;
          x1_re = _mm512_fmsub_pd(x1_re,b4_re,_mm512_mul_pd(x1_im,b4_im));
          x1_im = _mm512_fmadd_pd(tr,b4_im,_mm512_mul_pd(x1_im,b4_re)); }
        x2_re = LD(&in_re[8*K+k]);
        x2_im = LD(&in_im[8*K+k]);
        { __m512d tr = x2_re;
          x2_re = _mm512_fmsub_pd(x2_re,b8_re,_mm512_mul_pd(x2_im,b8_im));
          x2_im = _mm512_fmadd_pd(tr,b8_im,_mm512_mul_pd(x2_im,b8_re)); }
        x3_re = LD(&in_re[12*K+k]);
        x3_im = LD(&in_im[12*K+k]);
        __m512d w12_re, w12_im;
        w12_re = _mm512_fmsub_pd(b4_re,b8_re,_mm512_mul_pd(b4_im,b8_im));
        w12_im = _mm512_fmadd_pd(b4_re,b8_im,_mm512_mul_pd(b4_im,b8_re));
        { __m512d tr = x3_re;
          x3_re = _mm512_fmsub_pd(x3_re,w12_re,_mm512_mul_pd(x3_im,w12_im));
          x3_im = _mm512_fmadd_pd(tr,w12_im,_mm512_mul_pd(x3_im,w12_re)); }

        /* radix-4 n2=0 [fwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_add_pd(t1r,t3i); x1_im=_mm512_sub_pd(t1i,t3r);
          x3_re=_mm512_sub_pd(t1r,t3i); x3_im=_mm512_add_pd(t1i,t3r);
        }

        _mm512_store_pd(&spill_re[0*8], x0_re);
        _mm512_store_pd(&spill_im[0*8], x0_im);
        _mm512_store_pd(&spill_re[1*8], x1_re);
        _mm512_store_pd(&spill_im[1*8], x1_im);
        _mm512_store_pd(&spill_re[2*8], x2_re);
        _mm512_store_pd(&spill_im[2*8], x2_im);
        _mm512_store_pd(&spill_re[3*8], x3_re);
        _mm512_store_pd(&spill_im[3*8], x3_im);

        /* sub-FFT n2=1 */
        x0_re = LD(&in_re[1*K+k]);
        x0_im = LD(&in_im[1*K+k]);
        { __m512d tr = x0_re;
          x0_re = _mm512_fmsub_pd(x0_re,b1_re,_mm512_mul_pd(x0_im,b1_im));
          x0_im = _mm512_fmadd_pd(tr,b1_im,_mm512_mul_pd(x0_im,b1_re)); }
        x1_re = LD(&in_re[5*K+k]);
        x1_im = LD(&in_im[5*K+k]);
        __m512d w5_re, w5_im;
        w5_re = _mm512_fmsub_pd(b1_re,b4_re,_mm512_mul_pd(b1_im,b4_im));
        w5_im = _mm512_fmadd_pd(b1_re,b4_im,_mm512_mul_pd(b1_im,b4_re));
        { __m512d tr = x1_re;
          x1_re = _mm512_fmsub_pd(x1_re,w5_re,_mm512_mul_pd(x1_im,w5_im));
          x1_im = _mm512_fmadd_pd(tr,w5_im,_mm512_mul_pd(x1_im,w5_re)); }
        x2_re = LD(&in_re[9*K+k]);
        x2_im = LD(&in_im[9*K+k]);
        __m512d w9_re, w9_im;
        w9_re = _mm512_fmsub_pd(b1_re,b8_re,_mm512_mul_pd(b1_im,b8_im));
        w9_im = _mm512_fmadd_pd(b1_re,b8_im,_mm512_mul_pd(b1_im,b8_re));
        { __m512d tr = x2_re;
          x2_re = _mm512_fmsub_pd(x2_re,w9_re,_mm512_mul_pd(x2_im,w9_im));
          x2_im = _mm512_fmadd_pd(tr,w9_im,_mm512_mul_pd(x2_im,w9_re)); }
        x3_re = LD(&in_re[13*K+k]);
        x3_im = LD(&in_im[13*K+k]);
        __m512d w13_re, w13_im;
        w13_re = _mm512_fmsub_pd(w5_re,b8_re,_mm512_mul_pd(w5_im,b8_im));
        w13_im = _mm512_fmadd_pd(w5_re,b8_im,_mm512_mul_pd(w5_im,b8_re));
        { __m512d tr = x3_re;
          x3_re = _mm512_fmsub_pd(x3_re,w13_re,_mm512_mul_pd(x3_im,w13_im));
          x3_im = _mm512_fmadd_pd(tr,w13_im,_mm512_mul_pd(x3_im,w13_re)); }

        /* radix-4 n2=1 [fwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_add_pd(t1r,t3i); x1_im=_mm512_sub_pd(t1i,t3r);
          x3_re=_mm512_sub_pd(t1r,t3i); x3_im=_mm512_add_pd(t1i,t3r);
        }

        _mm512_store_pd(&spill_re[4*8], x0_re);
        _mm512_store_pd(&spill_im[4*8], x0_im);
        _mm512_store_pd(&spill_re[5*8], x1_re);
        _mm512_store_pd(&spill_im[5*8], x1_im);
        _mm512_store_pd(&spill_re[6*8], x2_re);
        _mm512_store_pd(&spill_im[6*8], x2_im);
        _mm512_store_pd(&spill_re[7*8], x3_re);
        _mm512_store_pd(&spill_im[7*8], x3_im);

        /* sub-FFT n2=2 */
        x0_re = LD(&in_re[2*K+k]);
        x0_im = LD(&in_im[2*K+k]);
        { __m512d tr = x0_re;
          x0_re = _mm512_fmsub_pd(x0_re,b2_re,_mm512_mul_pd(x0_im,b2_im));
          x0_im = _mm512_fmadd_pd(tr,b2_im,_mm512_mul_pd(x0_im,b2_re)); }
        x1_re = LD(&in_re[6*K+k]);
        x1_im = LD(&in_im[6*K+k]);
        __m512d w6_re, w6_im;
        w6_re = _mm512_fmsub_pd(b2_re,b4_re,_mm512_mul_pd(b2_im,b4_im));
        w6_im = _mm512_fmadd_pd(b2_re,b4_im,_mm512_mul_pd(b2_im,b4_re));
        { __m512d tr = x1_re;
          x1_re = _mm512_fmsub_pd(x1_re,w6_re,_mm512_mul_pd(x1_im,w6_im));
          x1_im = _mm512_fmadd_pd(tr,w6_im,_mm512_mul_pd(x1_im,w6_re)); }
        x2_re = LD(&in_re[10*K+k]);
        x2_im = LD(&in_im[10*K+k]);
        __m512d w10_re, w10_im;
        w10_re = _mm512_fmsub_pd(b2_re,b8_re,_mm512_mul_pd(b2_im,b8_im));
        w10_im = _mm512_fmadd_pd(b2_re,b8_im,_mm512_mul_pd(b2_im,b8_re));
        { __m512d tr = x2_re;
          x2_re = _mm512_fmsub_pd(x2_re,w10_re,_mm512_mul_pd(x2_im,w10_im));
          x2_im = _mm512_fmadd_pd(tr,w10_im,_mm512_mul_pd(x2_im,w10_re)); }
        x3_re = LD(&in_re[14*K+k]);
        x3_im = LD(&in_im[14*K+k]);
        __m512d w14_re, w14_im;
        w14_re = _mm512_fmsub_pd(w6_re,b8_re,_mm512_mul_pd(w6_im,b8_im));
        w14_im = _mm512_fmadd_pd(w6_re,b8_im,_mm512_mul_pd(w6_im,b8_re));
        { __m512d tr = x3_re;
          x3_re = _mm512_fmsub_pd(x3_re,w14_re,_mm512_mul_pd(x3_im,w14_im));
          x3_im = _mm512_fmadd_pd(tr,w14_im,_mm512_mul_pd(x3_im,w14_re)); }

        /* radix-4 n2=2 [fwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_add_pd(t1r,t3i); x1_im=_mm512_sub_pd(t1i,t3r);
          x3_re=_mm512_sub_pd(t1r,t3i); x3_im=_mm512_add_pd(t1i,t3r);
        }

        _mm512_store_pd(&spill_re[8*8], x0_re);
        _mm512_store_pd(&spill_im[8*8], x0_im);
        _mm512_store_pd(&spill_re[9*8], x1_re);
        _mm512_store_pd(&spill_im[9*8], x1_im);
        _mm512_store_pd(&spill_re[10*8], x2_re);
        _mm512_store_pd(&spill_im[10*8], x2_im);
        _mm512_store_pd(&spill_re[11*8], x3_re);
        _mm512_store_pd(&spill_im[11*8], x3_im);

        /* sub-FFT n2=3 */
        x0_re = LD(&in_re[3*K+k]);
        x0_im = LD(&in_im[3*K+k]);
        __m512d w3_re, w3_im;
        w3_re = _mm512_fmsub_pd(b1_re,b2_re,_mm512_mul_pd(b1_im,b2_im));
        w3_im = _mm512_fmadd_pd(b1_re,b2_im,_mm512_mul_pd(b1_im,b2_re));
        { __m512d tr = x0_re;
          x0_re = _mm512_fmsub_pd(x0_re,w3_re,_mm512_mul_pd(x0_im,w3_im));
          x0_im = _mm512_fmadd_pd(tr,w3_im,_mm512_mul_pd(x0_im,w3_re)); }
        x1_re = LD(&in_re[7*K+k]);
        x1_im = LD(&in_im[7*K+k]);
        __m512d w7_re, w7_im;
        w7_re = _mm512_fmsub_pd(w3_re,b4_re,_mm512_mul_pd(w3_im,b4_im));
        w7_im = _mm512_fmadd_pd(w3_re,b4_im,_mm512_mul_pd(w3_im,b4_re));
        { __m512d tr = x1_re;
          x1_re = _mm512_fmsub_pd(x1_re,w7_re,_mm512_mul_pd(x1_im,w7_im));
          x1_im = _mm512_fmadd_pd(tr,w7_im,_mm512_mul_pd(x1_im,w7_re)); }
        x2_re = LD(&in_re[11*K+k]);
        x2_im = LD(&in_im[11*K+k]);
        __m512d w11_re, w11_im;
        w11_re = _mm512_fmsub_pd(w3_re,b8_re,_mm512_mul_pd(w3_im,b8_im));
        w11_im = _mm512_fmadd_pd(w3_re,b8_im,_mm512_mul_pd(w3_im,b8_re));
        { __m512d tr = x2_re;
          x2_re = _mm512_fmsub_pd(x2_re,w11_re,_mm512_mul_pd(x2_im,w11_im));
          x2_im = _mm512_fmadd_pd(tr,w11_im,_mm512_mul_pd(x2_im,w11_re)); }
        x3_re = LD(&in_re[15*K+k]);
        x3_im = LD(&in_im[15*K+k]);
        __m512d w15_re, w15_im;
        w15_re = _mm512_fmsub_pd(w7_re,b8_re,_mm512_mul_pd(w7_im,b8_im));
        w15_im = _mm512_fmadd_pd(w7_re,b8_im,_mm512_mul_pd(w7_im,b8_re));
        { __m512d tr = x3_re;
          x3_re = _mm512_fmsub_pd(x3_re,w15_re,_mm512_mul_pd(x3_im,w15_im));
          x3_im = _mm512_fmadd_pd(tr,w15_im,_mm512_mul_pd(x3_im,w15_re)); }

        /* radix-4 n2=3 [fwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_add_pd(t1r,t3i); x1_im=_mm512_sub_pd(t1i,t3r);
          x3_re=_mm512_sub_pd(t1r,t3i); x3_im=_mm512_add_pd(t1i,t3r);
        }

        _mm512_store_pd(&spill_re[12*8], x0_re);
        _mm512_store_pd(&spill_im[12*8], x0_im);
        _mm512_store_pd(&spill_re[13*8], x1_re);
        _mm512_store_pd(&spill_im[13*8], x1_im);
        _mm512_store_pd(&spill_re[14*8], x2_re);
        _mm512_store_pd(&spill_im[14*8], x2_im);
        _mm512_store_pd(&spill_re[15*8], x3_re);
        _mm512_store_pd(&spill_im[15*8], x3_im);

        /* PASS 2 */

        /* column k1=0 */
        x0_re = _mm512_load_pd(&spill_re[0*8]);
        x0_im = _mm512_load_pd(&spill_im[0*8]);
        x1_re = _mm512_load_pd(&spill_re[4*8]);
        x1_im = _mm512_load_pd(&spill_im[4*8]);
        x2_re = _mm512_load_pd(&spill_re[8*8]);
        x2_im = _mm512_load_pd(&spill_im[8*8]);
        x3_re = _mm512_load_pd(&spill_re[12*8]);
        x3_im = _mm512_load_pd(&spill_im[12*8]);

        /* radix-4 k1=0 [fwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_add_pd(t1r,t3i); x1_im=_mm512_sub_pd(t1i,t3r);
          x3_re=_mm512_sub_pd(t1r,t3i); x3_im=_mm512_add_pd(t1i,t3r);
        }

        ST(&out_re[0*K+k], x0_re);
        ST(&out_im[0*K+k], x0_im);
        ST(&out_re[4*K+k], x1_re);
        ST(&out_im[4*K+k], x1_im);
        ST(&out_re[8*K+k], x2_re);
        ST(&out_im[8*K+k], x2_im);
        ST(&out_re[12*K+k], x3_re);
        ST(&out_im[12*K+k], x3_im);

        /* column k1=1 */
        x0_re = _mm512_load_pd(&spill_re[1*8]);
        x0_im = _mm512_load_pd(&spill_im[1*8]);
        x1_re = _mm512_load_pd(&spill_re[5*8]);
        x1_im = _mm512_load_pd(&spill_im[5*8]);
        x2_re = _mm512_load_pd(&spill_re[9*8]);
        x2_im = _mm512_load_pd(&spill_im[9*8]);
        x3_re = _mm512_load_pd(&spill_re[13*8]);
        x3_im = _mm512_load_pd(&spill_im[13*8]);

        { __m512d tr=x1_re;
          x1_re=_mm512_fmsub_pd(x1_re,tw_W16_1_re,_mm512_mul_pd(x1_im,tw_W16_1_im));
          x1_im=_mm512_fmadd_pd(tr,tw_W16_1_im,_mm512_mul_pd(x1_im,tw_W16_1_re)); }
        { __m512d tr=x2_re,ti=x2_im;
          x2_re=_mm512_mul_pd(_mm512_add_pd(tr,ti),sqrt2_inv); x2_im=_mm512_mul_pd(_mm512_sub_pd(ti,tr),sqrt2_inv); }
        { __m512d tr=x3_re;
          x3_re=_mm512_fmsub_pd(x3_re,tw_W16_3_re,_mm512_mul_pd(x3_im,tw_W16_3_im));
          x3_im=_mm512_fmadd_pd(tr,tw_W16_3_im,_mm512_mul_pd(x3_im,tw_W16_3_re)); }

        /* radix-4 k1=1 [fwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_add_pd(t1r,t3i); x1_im=_mm512_sub_pd(t1i,t3r);
          x3_re=_mm512_sub_pd(t1r,t3i); x3_im=_mm512_add_pd(t1i,t3r);
        }

        ST(&out_re[1*K+k], x0_re);
        ST(&out_im[1*K+k], x0_im);
        ST(&out_re[5*K+k], x1_re);
        ST(&out_im[5*K+k], x1_im);
        ST(&out_re[9*K+k], x2_re);
        ST(&out_im[9*K+k], x2_im);
        ST(&out_re[13*K+k], x3_re);
        ST(&out_im[13*K+k], x3_im);

        /* column k1=2 */
        x0_re = _mm512_load_pd(&spill_re[2*8]);
        x0_im = _mm512_load_pd(&spill_im[2*8]);
        x1_re = _mm512_load_pd(&spill_re[6*8]);
        x1_im = _mm512_load_pd(&spill_im[6*8]);
        x2_re = _mm512_load_pd(&spill_re[10*8]);
        x2_im = _mm512_load_pd(&spill_im[10*8]);
        x3_re = _mm512_load_pd(&spill_re[14*8]);
        x3_im = _mm512_load_pd(&spill_im[14*8]);

        { __m512d tr=x1_re,ti=x1_im;
          x1_re=_mm512_mul_pd(_mm512_add_pd(tr,ti),sqrt2_inv); x1_im=_mm512_mul_pd(_mm512_sub_pd(ti,tr),sqrt2_inv); }
        { __m512d t=x2_re; x2_re=x2_im; x2_im=_mm512_xor_pd(t,sign_flip); }
        { __m512d tr=x3_re,ti=x3_im;
          x3_re=_mm512_mul_pd(_mm512_sub_pd(ti,tr),sqrt2_inv); x3_im=_mm512_xor_pd(_mm512_mul_pd(_mm512_add_pd(tr,ti),sqrt2_inv),sign_flip); }

        /* radix-4 k1=2 [fwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_add_pd(t1r,t3i); x1_im=_mm512_sub_pd(t1i,t3r);
          x3_re=_mm512_sub_pd(t1r,t3i); x3_im=_mm512_add_pd(t1i,t3r);
        }

        ST(&out_re[2*K+k], x0_re);
        ST(&out_im[2*K+k], x0_im);
        ST(&out_re[6*K+k], x1_re);
        ST(&out_im[6*K+k], x1_im);
        ST(&out_re[10*K+k], x2_re);
        ST(&out_im[10*K+k], x2_im);
        ST(&out_re[14*K+k], x3_re);
        ST(&out_im[14*K+k], x3_im);

        /* column k1=3 */
        x0_re = _mm512_load_pd(&spill_re[3*8]);
        x0_im = _mm512_load_pd(&spill_im[3*8]);
        x1_re = _mm512_load_pd(&spill_re[7*8]);
        x1_im = _mm512_load_pd(&spill_im[7*8]);
        x2_re = _mm512_load_pd(&spill_re[11*8]);
        x2_im = _mm512_load_pd(&spill_im[11*8]);
        x3_re = _mm512_load_pd(&spill_re[15*8]);
        x3_im = _mm512_load_pd(&spill_im[15*8]);

        { __m512d tr=x1_re;
          x1_re=_mm512_fmsub_pd(x1_re,tw_W16_3_re,_mm512_mul_pd(x1_im,tw_W16_3_im));
          x1_im=_mm512_fmadd_pd(tr,tw_W16_3_im,_mm512_mul_pd(x1_im,tw_W16_3_re)); }
        { __m512d tr=x2_re,ti=x2_im;
          x2_re=_mm512_mul_pd(_mm512_sub_pd(ti,tr),sqrt2_inv); x2_im=_mm512_xor_pd(_mm512_mul_pd(_mm512_add_pd(tr,ti),sqrt2_inv),sign_flip); }
        { __m512d tr=x3_re;
          x3_re=_mm512_fmsub_pd(x3_re,tw_W16_9_re,_mm512_mul_pd(x3_im,tw_W16_9_im));
          x3_im=_mm512_fmadd_pd(tr,tw_W16_9_im,_mm512_mul_pd(x3_im,tw_W16_9_re)); }

        /* radix-4 k1=3 [fwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_add_pd(t1r,t3i); x1_im=_mm512_sub_pd(t1i,t3r);
          x3_re=_mm512_sub_pd(t1r,t3i); x3_im=_mm512_add_pd(t1i,t3r);
        }

        ST(&out_re[3*K+k], x0_re);
        ST(&out_im[3*K+k], x0_im);
        ST(&out_re[7*K+k], x1_re);
        ST(&out_im[7*K+k], x1_im);
        ST(&out_re[11*K+k], x2_re);
        ST(&out_im[11*K+k], x2_im);
        ST(&out_re[15*K+k], x3_re);
        ST(&out_im[15*K+k], x3_im);

    }
}

static __attribute__((target("avx512f,avx512dq,fma"))) void
radix16_tw_log3_dit_kernel_bwd_avx512(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    const double * __restrict__ base_tw_re, const double * __restrict__ base_tw_im,
    size_t K)
{
    const __m512d sign_flip = _mm512_set1_pd(-0.0);
    const __m512d sqrt2_inv = _mm512_set1_pd(0.70710678118654752440);

    __attribute__((aligned(64))) double spill_re[128];
    __attribute__((aligned(64))) double spill_im[128];

    __m512d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im;

    /* Hoisted internal W16 broadcasts [bwd] */
    const __m512d tw_W16_1_re = _mm512_set1_pd(W16_1_re);
    const __m512d tw_W16_1_im = _mm512_set1_pd(W16_1_im);
    const __m512d tw_W16_3_re = _mm512_set1_pd(W16_3_re);
    const __m512d tw_W16_3_im = _mm512_set1_pd(W16_3_im);
    const __m512d tw_W16_9_re = _mm512_set1_pd(W16_9_re);
    const __m512d tw_W16_9_im = _mm512_set1_pd(W16_9_im);

    for (size_t k = 0; k < K; k += 8) {
        /* Load 4 log3 base twiddles: W^1, W^2, W^4, W^8 */
        const __m512d b1_re = _mm512_load_pd(&base_tw_re[0*K+k]);
        const __m512d b1_im = _mm512_load_pd(&base_tw_im[0*K+k]);
        const __m512d b2_re = _mm512_load_pd(&base_tw_re[1*K+k]);
        const __m512d b2_im = _mm512_load_pd(&base_tw_im[1*K+k]);
        const __m512d b4_re = _mm512_load_pd(&base_tw_re[2*K+k]);
        const __m512d b4_im = _mm512_load_pd(&base_tw_im[2*K+k]);
        const __m512d b8_re = _mm512_load_pd(&base_tw_re[3*K+k]);
        const __m512d b8_im = _mm512_load_pd(&base_tw_im[3*K+k]);

        __m512d tw_dr, tw_di;

        /* sub-FFT n2=0 */
        x0_re = LD(&in_re[0*K+k]);
        x0_im = LD(&in_im[0*K+k]);
        x1_re = LD(&in_re[4*K+k]);
        x1_im = LD(&in_im[4*K+k]);
        { __m512d tr = x1_re;
          x1_re = _mm512_fmadd_pd(x1_re,b4_re,_mm512_mul_pd(x1_im,b4_im));
          x1_im = _mm512_fmsub_pd(x1_im,b4_re,_mm512_mul_pd(tr,b4_im)); }
        x2_re = LD(&in_re[8*K+k]);
        x2_im = LD(&in_im[8*K+k]);
        { __m512d tr = x2_re;
          x2_re = _mm512_fmadd_pd(x2_re,b8_re,_mm512_mul_pd(x2_im,b8_im));
          x2_im = _mm512_fmsub_pd(x2_im,b8_re,_mm512_mul_pd(tr,b8_im)); }
        x3_re = LD(&in_re[12*K+k]);
        x3_im = LD(&in_im[12*K+k]);
        __m512d w12_re, w12_im;
        w12_re = _mm512_fmsub_pd(b4_re,b8_re,_mm512_mul_pd(b4_im,b8_im));
        w12_im = _mm512_fmadd_pd(b4_re,b8_im,_mm512_mul_pd(b4_im,b8_re));
        { __m512d tr = x3_re;
          x3_re = _mm512_fmadd_pd(x3_re,w12_re,_mm512_mul_pd(x3_im,w12_im));
          x3_im = _mm512_fmsub_pd(x3_im,w12_re,_mm512_mul_pd(tr,w12_im)); }

        /* radix-4 n2=0 [bwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_sub_pd(t1r,t3i); x1_im=_mm512_add_pd(t1i,t3r);
          x3_re=_mm512_add_pd(t1r,t3i); x3_im=_mm512_sub_pd(t1i,t3r);
        }

        _mm512_store_pd(&spill_re[0*8], x0_re);
        _mm512_store_pd(&spill_im[0*8], x0_im);
        _mm512_store_pd(&spill_re[1*8], x1_re);
        _mm512_store_pd(&spill_im[1*8], x1_im);
        _mm512_store_pd(&spill_re[2*8], x2_re);
        _mm512_store_pd(&spill_im[2*8], x2_im);
        _mm512_store_pd(&spill_re[3*8], x3_re);
        _mm512_store_pd(&spill_im[3*8], x3_im);

        /* sub-FFT n2=1 */
        x0_re = LD(&in_re[1*K+k]);
        x0_im = LD(&in_im[1*K+k]);
        { __m512d tr = x0_re;
          x0_re = _mm512_fmadd_pd(x0_re,b1_re,_mm512_mul_pd(x0_im,b1_im));
          x0_im = _mm512_fmsub_pd(x0_im,b1_re,_mm512_mul_pd(tr,b1_im)); }
        x1_re = LD(&in_re[5*K+k]);
        x1_im = LD(&in_im[5*K+k]);
        __m512d w5_re, w5_im;
        w5_re = _mm512_fmsub_pd(b1_re,b4_re,_mm512_mul_pd(b1_im,b4_im));
        w5_im = _mm512_fmadd_pd(b1_re,b4_im,_mm512_mul_pd(b1_im,b4_re));
        { __m512d tr = x1_re;
          x1_re = _mm512_fmadd_pd(x1_re,w5_re,_mm512_mul_pd(x1_im,w5_im));
          x1_im = _mm512_fmsub_pd(x1_im,w5_re,_mm512_mul_pd(tr,w5_im)); }
        x2_re = LD(&in_re[9*K+k]);
        x2_im = LD(&in_im[9*K+k]);
        __m512d w9_re, w9_im;
        w9_re = _mm512_fmsub_pd(b1_re,b8_re,_mm512_mul_pd(b1_im,b8_im));
        w9_im = _mm512_fmadd_pd(b1_re,b8_im,_mm512_mul_pd(b1_im,b8_re));
        { __m512d tr = x2_re;
          x2_re = _mm512_fmadd_pd(x2_re,w9_re,_mm512_mul_pd(x2_im,w9_im));
          x2_im = _mm512_fmsub_pd(x2_im,w9_re,_mm512_mul_pd(tr,w9_im)); }
        x3_re = LD(&in_re[13*K+k]);
        x3_im = LD(&in_im[13*K+k]);
        __m512d w13_re, w13_im;
        w13_re = _mm512_fmsub_pd(w5_re,b8_re,_mm512_mul_pd(w5_im,b8_im));
        w13_im = _mm512_fmadd_pd(w5_re,b8_im,_mm512_mul_pd(w5_im,b8_re));
        { __m512d tr = x3_re;
          x3_re = _mm512_fmadd_pd(x3_re,w13_re,_mm512_mul_pd(x3_im,w13_im));
          x3_im = _mm512_fmsub_pd(x3_im,w13_re,_mm512_mul_pd(tr,w13_im)); }

        /* radix-4 n2=1 [bwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_sub_pd(t1r,t3i); x1_im=_mm512_add_pd(t1i,t3r);
          x3_re=_mm512_add_pd(t1r,t3i); x3_im=_mm512_sub_pd(t1i,t3r);
        }

        _mm512_store_pd(&spill_re[4*8], x0_re);
        _mm512_store_pd(&spill_im[4*8], x0_im);
        _mm512_store_pd(&spill_re[5*8], x1_re);
        _mm512_store_pd(&spill_im[5*8], x1_im);
        _mm512_store_pd(&spill_re[6*8], x2_re);
        _mm512_store_pd(&spill_im[6*8], x2_im);
        _mm512_store_pd(&spill_re[7*8], x3_re);
        _mm512_store_pd(&spill_im[7*8], x3_im);

        /* sub-FFT n2=2 */
        x0_re = LD(&in_re[2*K+k]);
        x0_im = LD(&in_im[2*K+k]);
        { __m512d tr = x0_re;
          x0_re = _mm512_fmadd_pd(x0_re,b2_re,_mm512_mul_pd(x0_im,b2_im));
          x0_im = _mm512_fmsub_pd(x0_im,b2_re,_mm512_mul_pd(tr,b2_im)); }
        x1_re = LD(&in_re[6*K+k]);
        x1_im = LD(&in_im[6*K+k]);
        __m512d w6_re, w6_im;
        w6_re = _mm512_fmsub_pd(b2_re,b4_re,_mm512_mul_pd(b2_im,b4_im));
        w6_im = _mm512_fmadd_pd(b2_re,b4_im,_mm512_mul_pd(b2_im,b4_re));
        { __m512d tr = x1_re;
          x1_re = _mm512_fmadd_pd(x1_re,w6_re,_mm512_mul_pd(x1_im,w6_im));
          x1_im = _mm512_fmsub_pd(x1_im,w6_re,_mm512_mul_pd(tr,w6_im)); }
        x2_re = LD(&in_re[10*K+k]);
        x2_im = LD(&in_im[10*K+k]);
        __m512d w10_re, w10_im;
        w10_re = _mm512_fmsub_pd(b2_re,b8_re,_mm512_mul_pd(b2_im,b8_im));
        w10_im = _mm512_fmadd_pd(b2_re,b8_im,_mm512_mul_pd(b2_im,b8_re));
        { __m512d tr = x2_re;
          x2_re = _mm512_fmadd_pd(x2_re,w10_re,_mm512_mul_pd(x2_im,w10_im));
          x2_im = _mm512_fmsub_pd(x2_im,w10_re,_mm512_mul_pd(tr,w10_im)); }
        x3_re = LD(&in_re[14*K+k]);
        x3_im = LD(&in_im[14*K+k]);
        __m512d w14_re, w14_im;
        w14_re = _mm512_fmsub_pd(w6_re,b8_re,_mm512_mul_pd(w6_im,b8_im));
        w14_im = _mm512_fmadd_pd(w6_re,b8_im,_mm512_mul_pd(w6_im,b8_re));
        { __m512d tr = x3_re;
          x3_re = _mm512_fmadd_pd(x3_re,w14_re,_mm512_mul_pd(x3_im,w14_im));
          x3_im = _mm512_fmsub_pd(x3_im,w14_re,_mm512_mul_pd(tr,w14_im)); }

        /* radix-4 n2=2 [bwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_sub_pd(t1r,t3i); x1_im=_mm512_add_pd(t1i,t3r);
          x3_re=_mm512_add_pd(t1r,t3i); x3_im=_mm512_sub_pd(t1i,t3r);
        }

        _mm512_store_pd(&spill_re[8*8], x0_re);
        _mm512_store_pd(&spill_im[8*8], x0_im);
        _mm512_store_pd(&spill_re[9*8], x1_re);
        _mm512_store_pd(&spill_im[9*8], x1_im);
        _mm512_store_pd(&spill_re[10*8], x2_re);
        _mm512_store_pd(&spill_im[10*8], x2_im);
        _mm512_store_pd(&spill_re[11*8], x3_re);
        _mm512_store_pd(&spill_im[11*8], x3_im);

        /* sub-FFT n2=3 */
        x0_re = LD(&in_re[3*K+k]);
        x0_im = LD(&in_im[3*K+k]);
        __m512d w3_re, w3_im;
        w3_re = _mm512_fmsub_pd(b1_re,b2_re,_mm512_mul_pd(b1_im,b2_im));
        w3_im = _mm512_fmadd_pd(b1_re,b2_im,_mm512_mul_pd(b1_im,b2_re));
        { __m512d tr = x0_re;
          x0_re = _mm512_fmadd_pd(x0_re,w3_re,_mm512_mul_pd(x0_im,w3_im));
          x0_im = _mm512_fmsub_pd(x0_im,w3_re,_mm512_mul_pd(tr,w3_im)); }
        x1_re = LD(&in_re[7*K+k]);
        x1_im = LD(&in_im[7*K+k]);
        __m512d w7_re, w7_im;
        w7_re = _mm512_fmsub_pd(w3_re,b4_re,_mm512_mul_pd(w3_im,b4_im));
        w7_im = _mm512_fmadd_pd(w3_re,b4_im,_mm512_mul_pd(w3_im,b4_re));
        { __m512d tr = x1_re;
          x1_re = _mm512_fmadd_pd(x1_re,w7_re,_mm512_mul_pd(x1_im,w7_im));
          x1_im = _mm512_fmsub_pd(x1_im,w7_re,_mm512_mul_pd(tr,w7_im)); }
        x2_re = LD(&in_re[11*K+k]);
        x2_im = LD(&in_im[11*K+k]);
        __m512d w11_re, w11_im;
        w11_re = _mm512_fmsub_pd(w3_re,b8_re,_mm512_mul_pd(w3_im,b8_im));
        w11_im = _mm512_fmadd_pd(w3_re,b8_im,_mm512_mul_pd(w3_im,b8_re));
        { __m512d tr = x2_re;
          x2_re = _mm512_fmadd_pd(x2_re,w11_re,_mm512_mul_pd(x2_im,w11_im));
          x2_im = _mm512_fmsub_pd(x2_im,w11_re,_mm512_mul_pd(tr,w11_im)); }
        x3_re = LD(&in_re[15*K+k]);
        x3_im = LD(&in_im[15*K+k]);
        __m512d w15_re, w15_im;
        w15_re = _mm512_fmsub_pd(w7_re,b8_re,_mm512_mul_pd(w7_im,b8_im));
        w15_im = _mm512_fmadd_pd(w7_re,b8_im,_mm512_mul_pd(w7_im,b8_re));
        { __m512d tr = x3_re;
          x3_re = _mm512_fmadd_pd(x3_re,w15_re,_mm512_mul_pd(x3_im,w15_im));
          x3_im = _mm512_fmsub_pd(x3_im,w15_re,_mm512_mul_pd(tr,w15_im)); }

        /* radix-4 n2=3 [bwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_sub_pd(t1r,t3i); x1_im=_mm512_add_pd(t1i,t3r);
          x3_re=_mm512_add_pd(t1r,t3i); x3_im=_mm512_sub_pd(t1i,t3r);
        }

        _mm512_store_pd(&spill_re[12*8], x0_re);
        _mm512_store_pd(&spill_im[12*8], x0_im);
        _mm512_store_pd(&spill_re[13*8], x1_re);
        _mm512_store_pd(&spill_im[13*8], x1_im);
        _mm512_store_pd(&spill_re[14*8], x2_re);
        _mm512_store_pd(&spill_im[14*8], x2_im);
        _mm512_store_pd(&spill_re[15*8], x3_re);
        _mm512_store_pd(&spill_im[15*8], x3_im);

        /* PASS 2 */

        /* column k1=0 */
        x0_re = _mm512_load_pd(&spill_re[0*8]);
        x0_im = _mm512_load_pd(&spill_im[0*8]);
        x1_re = _mm512_load_pd(&spill_re[4*8]);
        x1_im = _mm512_load_pd(&spill_im[4*8]);
        x2_re = _mm512_load_pd(&spill_re[8*8]);
        x2_im = _mm512_load_pd(&spill_im[8*8]);
        x3_re = _mm512_load_pd(&spill_re[12*8]);
        x3_im = _mm512_load_pd(&spill_im[12*8]);

        /* radix-4 k1=0 [bwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_sub_pd(t1r,t3i); x1_im=_mm512_add_pd(t1i,t3r);
          x3_re=_mm512_add_pd(t1r,t3i); x3_im=_mm512_sub_pd(t1i,t3r);
        }

        ST(&out_re[0*K+k], x0_re);
        ST(&out_im[0*K+k], x0_im);
        ST(&out_re[4*K+k], x1_re);
        ST(&out_im[4*K+k], x1_im);
        ST(&out_re[8*K+k], x2_re);
        ST(&out_im[8*K+k], x2_im);
        ST(&out_re[12*K+k], x3_re);
        ST(&out_im[12*K+k], x3_im);

        /* column k1=1 */
        x0_re = _mm512_load_pd(&spill_re[1*8]);
        x0_im = _mm512_load_pd(&spill_im[1*8]);
        x1_re = _mm512_load_pd(&spill_re[5*8]);
        x1_im = _mm512_load_pd(&spill_im[5*8]);
        x2_re = _mm512_load_pd(&spill_re[9*8]);
        x2_im = _mm512_load_pd(&spill_im[9*8]);
        x3_re = _mm512_load_pd(&spill_re[13*8]);
        x3_im = _mm512_load_pd(&spill_im[13*8]);

        { __m512d tr=x1_re;
          x1_re=_mm512_fmadd_pd(x1_re,tw_W16_1_re,_mm512_mul_pd(x1_im,tw_W16_1_im));
          x1_im=_mm512_fmsub_pd(x1_im,tw_W16_1_re,_mm512_mul_pd(tr,tw_W16_1_im)); }
        { __m512d tr=x2_re,ti=x2_im;
          x2_re=_mm512_mul_pd(_mm512_sub_pd(tr,ti),sqrt2_inv); x2_im=_mm512_mul_pd(_mm512_add_pd(tr,ti),sqrt2_inv); }
        { __m512d tr=x3_re;
          x3_re=_mm512_fmadd_pd(x3_re,tw_W16_3_re,_mm512_mul_pd(x3_im,tw_W16_3_im));
          x3_im=_mm512_fmsub_pd(x3_im,tw_W16_3_re,_mm512_mul_pd(tr,tw_W16_3_im)); }

        /* radix-4 k1=1 [bwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_sub_pd(t1r,t3i); x1_im=_mm512_add_pd(t1i,t3r);
          x3_re=_mm512_add_pd(t1r,t3i); x3_im=_mm512_sub_pd(t1i,t3r);
        }

        ST(&out_re[1*K+k], x0_re);
        ST(&out_im[1*K+k], x0_im);
        ST(&out_re[5*K+k], x1_re);
        ST(&out_im[5*K+k], x1_im);
        ST(&out_re[9*K+k], x2_re);
        ST(&out_im[9*K+k], x2_im);
        ST(&out_re[13*K+k], x3_re);
        ST(&out_im[13*K+k], x3_im);

        /* column k1=2 */
        x0_re = _mm512_load_pd(&spill_re[2*8]);
        x0_im = _mm512_load_pd(&spill_im[2*8]);
        x1_re = _mm512_load_pd(&spill_re[6*8]);
        x1_im = _mm512_load_pd(&spill_im[6*8]);
        x2_re = _mm512_load_pd(&spill_re[10*8]);
        x2_im = _mm512_load_pd(&spill_im[10*8]);
        x3_re = _mm512_load_pd(&spill_re[14*8]);
        x3_im = _mm512_load_pd(&spill_im[14*8]);

        { __m512d tr=x1_re,ti=x1_im;
          x1_re=_mm512_mul_pd(_mm512_sub_pd(tr,ti),sqrt2_inv); x1_im=_mm512_mul_pd(_mm512_add_pd(tr,ti),sqrt2_inv); }
        { __m512d t=x2_re; x2_re=_mm512_xor_pd(x2_im,sign_flip); x2_im=t; }
        { __m512d tr=x3_re,ti=x3_im;
          x3_re=_mm512_xor_pd(_mm512_mul_pd(_mm512_add_pd(tr,ti),sqrt2_inv),sign_flip); x3_im=_mm512_mul_pd(_mm512_sub_pd(tr,ti),sqrt2_inv); }

        /* radix-4 k1=2 [bwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_sub_pd(t1r,t3i); x1_im=_mm512_add_pd(t1i,t3r);
          x3_re=_mm512_add_pd(t1r,t3i); x3_im=_mm512_sub_pd(t1i,t3r);
        }

        ST(&out_re[2*K+k], x0_re);
        ST(&out_im[2*K+k], x0_im);
        ST(&out_re[6*K+k], x1_re);
        ST(&out_im[6*K+k], x1_im);
        ST(&out_re[10*K+k], x2_re);
        ST(&out_im[10*K+k], x2_im);
        ST(&out_re[14*K+k], x3_re);
        ST(&out_im[14*K+k], x3_im);

        /* column k1=3 */
        x0_re = _mm512_load_pd(&spill_re[3*8]);
        x0_im = _mm512_load_pd(&spill_im[3*8]);
        x1_re = _mm512_load_pd(&spill_re[7*8]);
        x1_im = _mm512_load_pd(&spill_im[7*8]);
        x2_re = _mm512_load_pd(&spill_re[11*8]);
        x2_im = _mm512_load_pd(&spill_im[11*8]);
        x3_re = _mm512_load_pd(&spill_re[15*8]);
        x3_im = _mm512_load_pd(&spill_im[15*8]);

        { __m512d tr=x1_re;
          x1_re=_mm512_fmadd_pd(x1_re,tw_W16_3_re,_mm512_mul_pd(x1_im,tw_W16_3_im));
          x1_im=_mm512_fmsub_pd(x1_im,tw_W16_3_re,_mm512_mul_pd(tr,tw_W16_3_im)); }
        { __m512d tr=x2_re,ti=x2_im;
          x2_re=_mm512_xor_pd(_mm512_mul_pd(_mm512_add_pd(tr,ti),sqrt2_inv),sign_flip); x2_im=_mm512_mul_pd(_mm512_sub_pd(tr,ti),sqrt2_inv); }
        { __m512d tr=x3_re;
          x3_re=_mm512_fmadd_pd(x3_re,tw_W16_9_re,_mm512_mul_pd(x3_im,tw_W16_9_im));
          x3_im=_mm512_fmsub_pd(x3_im,tw_W16_9_re,_mm512_mul_pd(tr,tw_W16_9_im)); }

        /* radix-4 k1=3 [bwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(x0_re,x2_re); t0i=_mm512_add_pd(x0_im,x2_im);
          t1r=_mm512_sub_pd(x0_re,x2_re); t1i=_mm512_sub_pd(x0_im,x2_im);
          t2r=_mm512_add_pd(x1_re,x3_re); t2i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t2r); x0_im=_mm512_add_pd(t0i,t2i);
          x2_re=_mm512_sub_pd(t0r,t2r); x2_im=_mm512_sub_pd(t0i,t2i);
          x1_re=_mm512_sub_pd(t1r,t3i); x1_im=_mm512_add_pd(t1i,t3r);
          x3_re=_mm512_add_pd(t1r,t3i); x3_im=_mm512_sub_pd(t1i,t3r);
        }

        ST(&out_re[3*K+k], x0_re);
        ST(&out_im[3*K+k], x0_im);
        ST(&out_re[7*K+k], x1_re);
        ST(&out_im[7*K+k], x1_im);
        ST(&out_re[11*K+k], x2_re);
        ST(&out_im[11*K+k], x2_im);
        ST(&out_re[15*K+k], x3_re);
        ST(&out_im[15*K+k], x3_im);

    }
}

#undef LD
#undef ST

#endif /* FFT_RADIX16_AVX512_DIT_TW_LOG3_H */
